import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

STORAGE_ACCOUNT_URL = os.environ["STORAGE_ACCOUNT_URL"]
SOURCE_CONTAINER = os.environ["SOURCE_CONTAINER"]
COSMOS_ENDPOINT = os.environ["COSMOS_ENDPOINT"]
COSMOS_DATABASE = os.environ["COSMOS_DATABASE"]
COSMOS_CONTAINER = os.environ["COSMOS_CONTAINER"]
EVENT_GRID_TOPIC_ENDPOINT = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]
EVENT_GRID_EVENT_TYPE = os.environ.get("EVENT_GRID_EVENT_TYPE", "Contoso.FileProcessed")
EVENT_GRID_SUBJECT_PREFIX = os.environ.get("EVENT_GRID_SUBJECT_PREFIX", "files/processed")
EVENT_GRID_DATA_VERSION = os.environ.get("EVENT_GRID_DATA_VERSION", "1.0")

credential = DefaultAzureCredential()

blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

database_client = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE)
container_client = database_client.create_container_if_not_exists(
    id=COSMOS_CONTAINER,
    partition_key=PartitionKey(path="/partitionKey"),
)


def _utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _safe_json_loads(content: str) -> Dict[str, Any]:
    try:
        parsed = json.loads(content)
        if isinstance(parsed, dict):
            return parsed
        return {"value": parsed}
    except Exception:
        return {"raw": content}


def _process_blob_content(blob_name: str, content: str) -> Dict[str, Any]:
    parsed = _safe_json_loads(content)
    return {
        "blobName": blob_name,
        "contentLength": len(content.encode("utf-8")),
        "processedAt": _utc_now_iso(),
        "parsed": parsed,
        "status": "processed",
    }


def _read_blob_text(container_name: str, blob_name: str) -> str:
    blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
    downloader = blob_client.download_blob()
    return downloader.content_as_text()


def _write_cosmos_document(document: Dict[str, Any]) -> Dict[str, Any]:
    return container_client.upsert_item(document)


def _send_event(subject: str, data: Dict[str, Any]) -> None:
    event = EventGridEvent(
        subject=subject,
        event_type=EVENT_GRID_EVENT_TYPE,
        data_version=EVENT_GRID_DATA_VERSION,
        data=data,
    )
    event_grid_client.send([event])


def _build_document(blob_name: str, result: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "id": f"{blob_name}:{int(datetime.now(timezone.utc).timestamp())}",
        "partitionKey": "file-processing",
        "blobName": blob_name,
        "result": result,
        "createdAt": _utc_now_iso(),
    }


@app.function_name(name="ProcessBlobHttp")
@app.route(route="process-blob", methods=["POST"])
def process_blob_http(req: func.HttpRequest) -> func.HttpResponse:
    logging.info("Received request to process blob.")

    try:
        body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Request body must be valid JSON."}),
            status_code=400,
            mimetype="application/json",
        )

